import datetime

bank_holidays = [datetime.date(2022,12,26), datetime.date(2022,12,27), datetime.date(2023,1,2)]
def is_working_day(d): return d.weekday() < 5 and d not in bank_holidays

def check_test_date(test_date):
    start = test_date - datetime.timedelta(days=10)
    week2_monday = test_date - datetime.timedelta(days=3)
    if not (is_working_day(start) and is_working_day(week2_monday)):
        return False
    working_count = sum(1 for i in range(11) if is_working_day(start + datetime.timedelta(days=i)))
    return working_count == 9

# Check early 2023 Thursdays
for month in [1,2]:
    for day in range(1,32):
        try:
            d = datetime.date(2023, month, day)
            if d.weekday() == 3 and check_test_date(d):
                print(f'Earliest valid: {d}')
                break
        except: pass

def alphabet_sum(text):
    return sum(ord(c) - ord('A') + 1 for c in text.upper() if 'A' <= c <= 'Z')
print('Note sum:', alphabet_sum('Note'))
print('Result:', 41 * 41 + 54)
